noncompliant:
// Using basic types without size indication
int function(unsigned short a) {
    char buffer[256];
    long offset = 0;
    return a + offset;
}

// Basic numeric types
void processData(int value, short index, long timestamp) {
    double result = value * 1.5;
    float precision = 0.001;
}

compliant:
// Using specific-length typedefs
#include <stdint.h>
uint32_t function(uint16_t a) {
    int8_t buffer[256];
    int64_t offset = 0;
    return a + offset;
}

// Specific size typedefs
#include <stdint.h>
void processData(int32_t value, int16_t index, int64_t timestamp) {
    double result = value * 1.5; // OK for floating point
    float precision = 0.001f;
}
